import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const Navbar = () => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  return (
    // 把背景顏色改成更有旅遊質感的顏色（例如 indigo 或 sky）
    <nav className="bg-indigo-700 text-white p-4 shadow-lg flex justify-between items-center">
      {/* 1. 修改系統名稱 */}
      <Link to="/" className="text-2xl font-bold tracking-tight">
         🌍 Sam's TPMS
      </Link>

      <div className="flex items-center">
        {user ? (
          <>
            {/* 2. 導覽到你剛改好的旅遊行程頁面 */}
            <Link to="/tours" className="mr-6 hover:text-indigo-200 transition">
              Tour Packages
            </Link>

            <Link to="/profile" className="mr-6 hover:text-indigo-200 transition">
              My Profile
            </Link>

            <div className="flex items-center border-l border-indigo-500 pl-6">
              <span className="mr-4 text-sm italic text-indigo-100">
                Hi, {user.name || 'User'}
              </span>
              <button
                onClick={handleLogout}
                className="bg-red-500 px-4 py-1.5 rounded-md text-sm font-medium hover:bg-red-600 transition shadow-sm"
              >
                Logout
              </button>
            </div>
          </>
        ) : (
          <>
            <Link to="/login" className="mr-4 hover:text-indigo-200">Login</Link>
            <Link
              to="/register"
              className="bg-green-500 px-4 py-2 rounded-md font-medium hover:bg-green-600 transition shadow-sm"
            >
              Get Started
            </Link>
          </>
        )}
      </div>
    </nav>
  );
};

export default Navbar;
